import{_ as a,o as e,c as o,a2 as r}from"./chunks/framework.4hJCcvDE.js";const p=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"blog/知识点_003-TCP与UDP在游戏中的应用.md","filePath":"blog/知识点_003-TCP与UDP在游戏中的应用.md","lastUpdated":1784835052000}'),l={name:"blog/知识点_003-TCP与UDP在游戏中的应用.md"};function i(d,t,n,h,P,s){return e(),o("div",null,[...t[0]||(t[0]=[r('<h2 id="引言" tabindex="-1">引言 <a class="header-anchor" href="#引言" aria-label="Permalink to &quot;引言&quot;">​</a></h2><p>网络通信是游戏开发中绕不开的话题，TCP 和 UDP 的选择是网络层设计的第一道选择题。这篇文章整理两者的核心差异、各自在游戏中的典型应用场景，以及实际项目中常见的组合方案。</p><h2 id="一、tcp-vs-udp-核心差异" tabindex="-1">一、TCP vs UDP 核心差异 <a class="header-anchor" href="#一、tcp-vs-udp-核心差异" aria-label="Permalink to &quot;一、TCP vs UDP 核心差异&quot;">​</a></h2><table tabindex="0"><thead><tr><th></th><th>TCP</th><th>UDP</th></tr></thead><tbody><tr><td>连接模型</td><td>面向连接（三次握手）</td><td>无连接</td></tr><tr><td>可靠性</td><td>保证送达、有序、不重复</td><td>不保证送达、不保证顺序、可能重复</td></tr><tr><td>流量控制</td><td>滑动窗口、拥塞控制</td><td>无</td></tr><tr><td>数据边界</td><td>字节流（需自行分包）</td><td>保留报文边界</td></tr><tr><td>头部开销</td><td>20 字节</td><td>8 字节</td></tr><tr><td>适用场景</td><td>文件传输、HTTP、登陆认证</td><td>实时游戏、音视频通话</td></tr></tbody></table><p>这些是教科书级别的结论，但在游戏开发中，真正影响选择的不是这些表层的差异，而是下面几个实际工程问题。</p><h2 id="二、游戏为什么偏爱-udp" tabindex="-1">二、游戏为什么偏爱 UDP <a class="header-anchor" href="#二、游戏为什么偏爱-udp" aria-label="Permalink to &quot;二、游戏为什么偏爱 UDP&quot;">​</a></h2><h3 id="_1-过时数据的价值为零" tabindex="-1">1. 过时数据的价值为零 <a class="header-anchor" href="#_1-过时数据的价值为零" aria-label="Permalink to &quot;1. 过时数据的价值为零&quot;">​</a></h3><p>游戏中最核心的数据类型是<strong>状态快照</strong>——角色位置、朝向、动作状态。这类数据有极强的时效性：上 100ms 的位置信息对当前帧的渲染和逻辑已经没有意义了。TCP 的可靠重传机制在这种情况下是负资产——如果一个位置包丢了，TCP 会阻塞后续数据直到重传成功，导致玩家看到的画面&quot;卡住&quot;，而不是平滑过渡到最新状态。</p><p>UDP 的思路是：丢了就丢了，发下一个。接收端总是处理最新到达的包，用插值和预测来平滑中间的状态变化。</p><h3 id="_2-自定义可靠性" tabindex="-1">2. 自定义可靠性 <a class="header-anchor" href="#_2-自定义可靠性" aria-label="Permalink to &quot;2. 自定义可靠性&quot;">​</a></h3><p>游戏通常不需要&quot;全都可靠&quot;，只需要&quot;关键信息可靠&quot;。UDP 给了你最大自由度——你可以在应用层对不同类型的消息做不同策略：</p><ul><li>移动位置：允许偶尔丢失（快发多次，丢一个不影响）</li><li>技能释放指令：必须可靠（应用层 ACK + 超时重传）</li><li>聊天消息：必须可靠、必须有序（应用层做序列号 + 排序）</li></ul><p>这种按需可靠比 TCP 的全局可靠高效得多——不需要为 90% 可以丢的数据付出 100% 可靠的代价。</p><h3 id="_3-避免-tcp-队头阻塞-head-of-line-blocking" tabindex="-1">3. 避免 TCP 队头阻塞（Head-of-Line Blocking） <a class="header-anchor" href="#_3-避免-tcp-队头阻塞-head-of-line-blocking" aria-label="Permalink to &quot;3. 避免 TCP 队头阻塞（Head-of-Line Blocking）&quot;">​</a></h3><p>TCP 保证字节流的严格有序性。如果包 #5 丢了，即使包 #6-#10 已经到了，应用层也读不到它们——内核会一直等 #5 重传成功。在 30ms 延迟的网络上，一次丢包可能造成 200ms+ 的卡顿。对于 FPS/MOBA 这类对延迟敏感的游戏，不可接受。</p><h2 id="三、但-tcp-在游戏中并非无用" tabindex="-1">三、但 TCP 在游戏中并非无用 <a class="header-anchor" href="#三、但-tcp-在游戏中并非无用" aria-label="Permalink to &quot;三、但 TCP 在游戏中并非无用&quot;">​</a></h2><h3 id="_1-mmo-大世界" tabindex="-1">1. MMO 大世界 <a class="header-anchor" href="#_1-mmo-大世界" aria-label="Permalink to &quot;1. MMO 大世界&quot;">​</a></h3><p>MMO 的战斗通常不走实时操作，而是指令下发 + 服务器确认的模式（客户端发送指令 → 服务器收集计算 → 广播状态）。这种模式下延迟容忍度相对较高（战斗逻辑帧率 5-20），而且 MMO 对&quot;数据不丢&quot;的要求比&quot;延迟极低&quot;更重——你不想玩家的交易、背包操作、任务状态因为丢包而出现不一致。</p><p>很多 MMO 使用 TCP 作为底层传输，客户端预测和插值在应用层做延迟平滑。</p><h3 id="_2-回合制和战棋" tabindex="-1">2. 回合制和战棋 <a class="header-anchor" href="#_2-回合制和战棋" aria-label="Permalink to &quot;2. 回合制和战棋&quot;">​</a></h3><p>《归义军传说》这种回合制 SRPG 对延迟完全不敏感——玩家做出操作后等 0.5 秒还是 0.2 秒看到结果，体验没有实质区别。TCP 的有序可靠特性恰好完美匹配这种场景。协议层面可以直接用可靠传输，省去应用层重传逻辑。</p><h3 id="_3-登陆-支付-更新" tabindex="-1">3. 登陆/支付/更新 <a class="header-anchor" href="#_3-登陆-支付-更新" aria-label="Permalink to &quot;3. 登陆/支付/更新&quot;">​</a></h3><p>任何时候涉及账号认证、充值扣费、资源下载，都必须是 TCP（或更上层的 HTTP/TLS）。这些场景数据完整性是第一位的，延迟多几百毫秒完全可接受。</p><h2 id="四、常见组合方案" tabindex="-1">四、常见组合方案 <a class="header-anchor" href="#四、常见组合方案" aria-label="Permalink to &quot;四、常见组合方案&quot;">​</a></h2><p>现实中大多数商业游戏不是&quot;TCP 还是 UDP&quot;，而是&quot;TCP 和 UDP 怎么配合&quot;：</p><ol><li><p><strong>TCP 做大厅 + UDP 做战斗</strong>：大厅（匹配、聊天、商城）用 TCP，进入战斗切 UDP。这是 FPS/MOBA 的标准做法。</p></li><li><p><strong>纯 TCP + 应用层优化</strong>：部分 MMO 和移动端游戏因为穿透 NAT/防火墙的复杂性，全部走 TCP，但在应用层做逻辑层分包（模仿 UDP 的消息边界）、时序无关的状态处理（类似 UDP 的&quot;只关心最新值&quot;）。</p></li><li><p><strong>RUDP / KCP / ENET 等中间方案</strong>：在 UDP 之上实现可靠层。KCP 是一个常见选择——牺牲部分带宽换取比 TCP 更低的延迟（更激进的超时重传、选择性 ACK）。适合延迟敏感但又需要一定可靠性保证的场景。</p></li><li><p><strong>WebSocket</strong>：H5 游戏和部分独立游戏的轻量选择。底层是 TCP，但提供了消息边界（帧协议封包），省去了 TCP 字节流的拆包逻辑。适合对延迟要求不高的网页游戏和回合制。</p></li></ol><h2 id="五、项目中实际遇到过的问题" tabindex="-1">五、项目中实际遇到过的问题 <a class="header-anchor" href="#五、项目中实际遇到过的问题" aria-label="Permalink to &quot;五、项目中实际遇到过的问题&quot;">​</a></h2><p>在 MMO 项目的实际开发中，真正花费精力的往往不是 TCP vs UDP 的选择，而是上层同步策略的设计：</p><ul><li>客户端预测的乐观执行和服务器确认冲突时怎么回滚（最常见的是&quot;我以为我移动到了这里，但服务器说不对&quot;）</li><li>技能前摇时间的调整（必须在服务器的逻辑帧时间 + 网络往返延迟内完成，前摇太短会让玩家觉得&quot;技能经常被打断&quot;）</li><li>移动平滑策略的选择（直接设置位置 vs 线性插值 vs 曲线插值，不同游戏体量不同）</li></ul><p>这些问题在传输层选型确定之后才会暴露，但它们往往比&quot;用 TCP 还是 UDP&quot;更影响最终手感。</p><h2 id="参考文献" tabindex="-1">参考文献 <a class="header-anchor" href="#参考文献" aria-label="Permalink to &quot;参考文献&quot;">​</a></h2><ul><li><a href="https://github.com/ljianshu/Blog/issues/61" target="_blank" rel="noreferrer">TCP和UDP比较</a></li><li><a href="https://gafferongames.com/categories/building-a-game-network-protocol/" target="_blank" rel="noreferrer">Gaffer on Games — Networking for Game Programmers</a></li><li><a href="https://github.com/skywind3000/kcp" target="_blank" rel="noreferrer">KCP — A Fast and Reliable ARQ Protocol</a></li></ul>',32)])])}const c=a(l,[["render",i]]);export{p as __pageData,c as default};
